async function handleAdminAssignTruck(request, env) {
  if (!isAdminAuthed(request, env)) return Response.redirect(new URL('/admin/login', request.url).toString(), 302);
  try {
    const form = await request.formData();
    const truck_id = form.get('truck_id');
    const driver_id = form.get('driver_id');
    if (!truck_id) return Response.redirect(new URL('/admin/dashboard#trucks', request.url).toString(), 302);
    if (!driver_id || driver_id === '') {
      // Unassign
      await sbPatch(env, 'trucks', `id=eq.${truck_id}`, { driver_id:null });
    } else {
      await sbPatch(env, 'trucks', `id=eq.${truck_id}`, { driver_id, status:'active' });
    }
  } catch(e) { console.error('assign-truck error', e.message); }
  return Response.redirect(new URL('/admin/dashboard#trucks', request.url).toString(), 302);
}

