// ═══════════════════════════════════════════════════════════════
// ADMIN LEADS CSV EXPORT
// ═══════════════════════════════════════════════════════════════

async function handleAdminLeadsExport(request, env) {
  if (!isAdminAuthed(request, env)) {
    return Response.redirect(new URL('/admin/login', request.url).toString(), 302);
  }
  const url = new URL(request.url);
  const filterStatus = url.searchParams.get('status') || '';
  const filterLang   = url.searchParams.get('lang')   || '';

  let query = 'select=*&order=created_at.desc';
  if (filterStatus === 'active') query += '&status=neq.unsubscribed';
  if (filterLang) query += `&lang=eq.${filterLang}`;

  const rows = await sbGet(env, 'email_captures', query);

  // Build CSV
  const headers = ['email','phone','language','status','sms_unsubscribed','source','offer_clicked','created_at'];
  const csvRows = [headers.join(',')];
  for (const r of rows) {
    const vals = [
      csvEsc(r.email||''),
      csvEsc(r.phone||''),
      csvEsc(r.lang||'en'),
      csvEsc(r.status||'active'),
      r.sms_unsubscribed ? 'true' : 'false',
      csvEsc(r.source||''),
      csvEsc(r.offer_clicked||''),
      csvEsc(r.created_at||''),
    ];
    csvRows.push(vals.join(','));
  }
  const csv = csvRows.join('\r\n');
  const suffix = filterStatus || filterLang ? `-${filterStatus||''}${filterLang||''}` : '-all';
  const filename = `qrperks-leads${suffix}-${new Date().toISOString().slice(0,10)}.csv`;
  return new Response(csv, {
    headers: {
      'Content-Type': 'text/csv; charset=utf-8',
      'Content-Disposition': `attachment; filename="${filename}"`,
    }
  });
}

function csvEsc(val) {
  const s = String(val);
  if (s.includes(',') || s.includes('"') || s.includes('\n')) {
    return '"' + s.replace(/"/g, '""') + '"';
  }
  return s;
}


// ═══════════════════════════════════════════════════════════════
// PERIOD STATS — /api/period-stats?period=day|week|month|year&scope=admin|driver&driver_id=...
// ═══════════════════════════════════════════════════════════════
async function handleApiPeriodStats(request, env) {
  try {
    const url = new URL(request.url);
    const period = url.searchParams.get('period') || 'week';
    const scope = url.searchParams.get('scope') || 'admin';
    const driverId = url.searchParams.get('driver_id') || null;

    const now = new Date();
    let cutoff;
    if (period === 'day')   cutoff = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    else if (period === 'month') cutoff = new Date(now.getFullYear(), now.getMonth(), 1);
    else if (period === 'year')  cutoff = new Date(now.getFullYear(), 0, 1);
    else cutoff = new Date(now.getTime() - 7*86400000); // week default
    const cutoffIso = cutoff.toISOString();

    if (scope === 'driver' && driverId) {
      const trucks = await sbGet(env, 'trucks', `driver_id=eq.${driverId}&select=id`);
      const truckIds = trucks.map(t => t.id);
      if (truckIds.length === 0) return jsonOk({ clicks:0, conversions:0, earnings_cents:0 });
      const tf = `truck_id=in.(${truckIds.join(',')})`;
      const [scans, convs] = await Promise.all([
        sbGet(env, 'scans', `${tf}&created_at=gte.${cutoffIso}&select=id,truck_id`),
        sbGet(env, 'conversions', `${tf}&created_at=gte.${cutoffIso}&select=commission_amount_cents,truck_id`),
      ]);
      const by_truck={};
      truckIds.forEach(tid=>{
        const ts=scans.filter(s=>s.truck_id===tid);
        const tc=convs.filter(c=>c.truck_id===tid);
        by_truck[tid]={clicks:ts.length,conversions:tc.length,earnings_cents:tc.reduce((s,c)=>s+(c.commission_amount_cents||0),0)};
      });
      return jsonOk({
        clicks: scans.length,
        conversions: convs.length,
        earnings_cents: convs.reduce((s,c)=>s+(c.commission_amount_cents||0),0),
        by_truck,
      });
    }

    // Admin scope — return per-org breakdown
    const GEO_ID = '4b83dcac-2739-4e19-a34e-b3c6a11006e3';
    const SPEEDY_ID = 'c85bb14e-e715-43c6-bb48-46c37a1acfc1';
    const [geoTrucks, speedyTrucks] = await Promise.all([
      sbGet(env, 'trucks', `driver_id=eq.${GEO_ID}&select=id`),
      sbGet(env, 'trucks', `driver_id=eq.${SPEEDY_ID}&select=id`),
    ]);
    const geoIds = geoTrucks.map(t=>t.id);
    const speedyIds = speedyTrucks.map(t=>t.id);
    const allIds = [...geoIds, ...speedyIds];
    if (allIds.length === 0) return jsonOk({
      geo:{clicks:0,conversions:0,earnings_cents:0},
      speedy:{clicks:0,conversions:0,earnings_cents:0},
    });
    const [scans, convs] = await Promise.all([
      sbGet(env, 'scans', `truck_id=in.(${allIds.join(',')})&created_at=gte.${cutoffIso}&select=id,truck_id`),
      sbGet(env, 'conversions', `truck_id=in.(${allIds.join(',')})&created_at=gte.${cutoffIso}&select=commission_amount_cents,truck_id`),
    ]);
    const orgStats = (ids) => ({
      clicks: scans.filter(s=>ids.includes(s.truck_id)).length,
      conversions: convs.filter(c=>ids.includes(c.truck_id)).length,
      earnings_cents: convs.filter(c=>ids.includes(c.truck_id)).reduce((s,c)=>s+(c.commission_amount_cents||0),0),
    });
    return jsonOk({ geo: orgStats(geoIds), speedy: orgStats(speedyIds) });
  } catch(e) {
    return jsonOk({ error: e.message }, 500);
  }
}

// ═══════════════════════════════════════════════════════════════
// ORG MARK PAID — /admin/org-mark-paid
// ═══════════════════════════════════════════════════════════════
async function handleAdminOrgMarkPaid(request, env) {
  if (!isAdminAuthed(request, env)) return Response.redirect(new URL('/admin/login', request.url).toString(), 302);
  const form = await request.formData();
  const driver_id = form.get('driver_id');
  if (!driver_id) return Response.redirect(new URL('/admin/dashboard', request.url).toString(), 302);
  // Mark all pending commissions for this driver as paid
  const pending = await sbGet(env, 'commissions', `driver_id=eq.${driver_id}&status=eq.pending&select=id`);
  for (const c of pending) {
    await sbPatch(env, 'commissions', `id=eq.${c.id}`, { status:'paid', paid_at:new Date().toISOString() });
  }
  return Response.redirect(new URL('/admin/dashboard#payments', request.url).toString(), 302);
}

async function handleAdminPayDriver(request, env) {
  if (!isAdminAuthed(request, env)) return jsonOk({ ok:false, error:'Unauthorized' });
  let body;
  try { body = await request.json(); } catch(e) { return jsonOk({ ok:false, error:'Invalid JSON' }); }
  const { driver_id, org_name, amount_cents, payment_reference, notes, period_start, period_end } = body;
  if (!driver_id || !amount_cents || !payment_reference) {
    return jsonOk({ ok:false, error:'driver_id, amount_cents, and payment_reference are required' });
  }
  try {
    // Look up driver's payment method
    const driver = await sbGetOne(env, 'drivers', `id=eq.${driver_id}&select=id,payment_method_type,payment_details_paypal,payment_details_bank_name`);
    if (!driver) return jsonOk({ ok:false, error:'Driver not found' });
    const paymentMethod = driver.payment_method_type || 'manual';

    // Insert payout record
    const now = new Date().toISOString();
    await sbPost(env, 'payouts', {
      driver_id,
      organization: org_name || null,
      amount_cents: Math.round(amount_cents),
      period_start: period_start || null,
      period_end: period_end || null,
      payment_method: paymentMethod,
      payment_reference,
      status: 'paid',
      notes: notes || null,
      paid_by: 'admin',
      paid_at: now,
    });

    // Mark all pending commissions for this driver as paid
    await sbPatch(env, 'commissions', `driver_id=eq.${driver_id}&status=eq.pending`, { status:'paid' });

    return jsonOk({ ok:true });
  } catch(e) {
    console.error('handleAdminPayDriver error:', e.message);
    return jsonOk({ ok:false, error:'Server error: ' + e.message });
  }
}

async function handleApiStats(request, env) {
  try {
    const [drivers, scans, captures, commissions, convRows] = await Promise.all([
      sbGet(env, 'drivers', 'select=id,status'),
      sbGet(env, 'scans', 'select=id,created_at&order=created_at.desc&limit=1000'),
      sbGet(env, 'email_captures', 'select=id,created_at&order=created_at.desc&limit=500'),
      sbGet(env, 'commissions', 'select=driver_amount_cents,status'),
      sbGet(env, 'conversions', 'select=gross_amount_cents,commission_amount_cents,status,offer_name'),
    ]);
    const now = new Date();
    const day = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const week = new Date(day.getTime() - 6 * 86400000);
    const scansToday = scans.filter(s=>new Date(s.created_at)>=day).length;
    const scansWeek  = scans.filter(s=>new Date(s.created_at)>=week).length;
    const leadsToday = captures.filter(c=>new Date(c.created_at)>=day).length;
    const pendingPay = commissions.filter(c=>c.status==='pending').reduce((s,c)=>s+(c.driver_amount_cents||0),0);
    const totalRevCents = convRows.reduce((s,c)=>s+(c.gross_amount_cents||0),0);
    const pendingCommCents = convRows.filter(c=>c.status==='pending').reduce((s,c)=>s+(c.commission_amount_cents||0),0);
    const convsByOffer = convRows.reduce((m,c)=>{const k=c.offer_name||'unknown';m[k]=(m[k]||0)+1;return m;},{});
    return jsonOk({
      drivers_total: drivers.length,
      drivers_active: drivers.filter(d=>d.status==='active').length,
      scans_today: scansToday,
      scans_week: scansWeek,
      leads_total: captures.length,
      leads_today: leadsToday,
      commissions_pending_cents: pendingPay,
      total_conversions: convRows.length,
      total_revenue_cents: totalRevCents,
      total_commissions_pending_cents: pendingCommCents,
      conversions_by_offer: convsByOffer,
      as_of: now.toISOString()
    });
  } catch(e) {
    return jsonOk({ error: e.message }, 500);
  }
}

// ═══════════════════════════════════════════════════════════════
// MAXBOUNTY POSTBACK — /api/conversion
// ═══════════════════════════════════════════════════════════════

async function handleApiConversion(request, env) {
  const url    = new URL(request.url);
  const subid  = url.searchParams.get('subid')  || '';
  const offer  = url.searchParams.get('offer')  || '';
  const payout = url.searchParams.get('payout') || '';
  const token  = url.searchParams.get('token')  || '';

  // Token check — prevent spoofed postbacks
  if (!env.POSTBACK_SECRET || token !== env.POSTBACK_SECRET) {
    return new Response('Forbidden', { status: 403 });
  }

  // Validate subid format: qrp_t1..qrp_t50
  if (!/^qrp_t[0-9]+$/.test(subid)) {
    return new Response('Bad Request: invalid subid', { status: 400 });
  }

  // Validate payout
  const payoutFloat = parseFloat(payout);
  if (isNaN(payoutFloat) || payoutFloat <= 0) {
    return new Response('Bad Request: invalid payout', { status: 400 });
  }

  const payoutCents     = Math.round(payoutFloat * 100);
  const commissionCents = Math.floor(payoutCents * 0.20);
  const truckId         = subid.replace('qrp_', ''); // "qrp_t3" → "t3"

  try {
    // Deduplication: skip if same subid+offer already processed within 60s
    const cutoff = new Date(Date.now() - 60000).toISOString();
    const dupe = await sbGetOne(env, 'conversions',
      `subid=eq.${encodeURIComponent(subid)}&offer_name=eq.${encodeURIComponent(offer)}&created_at=gte.${cutoff}&select=id`);
    if (dupe) {
      console.log(`postback dedup: ${subid}/${offer} already processed within 60s`);
      return new Response('OK', { status: 200 });
    }

    // Resolve truck → driver
    const truck    = await sbGetOne(env, 'trucks', `id=eq.${truckId}&select=id,driver_id`);
    const driverId = truck?.driver_id || null;

    if (!truck) {
      console.log(`postback: unknown truck ${truckId} — logging conversion without driver`);
    }

    // Write conversion row (affiliate_id omitted — FK to affiliates table; use offer_name instead)
    const convRow = {
      truck_id:              truckId,
      driver_id:             driverId,
      offer_name:            offer,
      gross_amount_cents:    payoutCents,
      commission_amount_cents: commissionCents,
      subid:                 subid,
      status:                'pending',
      commission_calculated: false,
    };
    const conv = await sbPost(env, 'conversions', convRow);

    if (driverId) {
      // Create commissions row (powers driver dashboard history)
      await sbPost(env, 'commissions', {
        driver_id:           driverId,
        conversion_id:       conv?.id || null,
        type:                'truck_conversion',
        gross_amount_cents:  payoutCents,
        driver_amount_cents: commissionCents,
        status:              'pending',
      });

      // Mark conversion commission_calculated so engine doesn't double-process
      if (conv?.id) {
        await sbPatch(env, 'conversions', `id=eq.${conv.id}`, { commission_calculated: true });
      }

      // Update driver total_earnings_cents AND direct_earnings (dollars, numeric column)
      const driver  = await sbGetOne(env, 'drivers', `id=eq.${driverId}&select=total_earnings_cents,direct_earnings,referred_by_driver_id`);
      const current = driver?.total_earnings_cents || 0;
      const currentDirect = parseFloat(driver?.direct_earnings || 0);
      await sbPatch(env, 'drivers', `id=eq.${driverId}`, {
        total_earnings_cents: current + commissionCents,
        direct_earnings: parseFloat((currentDirect + commissionCents / 100).toFixed(4)),
      });

      // Referral override (10% to referrer)
      // Primary: driver.referred_by_driver_id; fallback: referrals table
      let referrerId = driver?.referred_by_driver_id || null;
      if (!referrerId) {
        const refs = await sbGet(env, 'referrals', `referred_driver_id=eq.${driverId}&select=referrer_driver_id`);
        referrerId = refs[0]?.referrer_driver_id || null;
      }
      if (referrerId) {
        const refAmt = Math.floor(payoutCents * 0.10);
        await sbPost(env, 'commissions', {
          driver_id:           referrerId,
          conversion_id:       conv?.id || null,
          type:                'referral_override',
          gross_amount_cents:  payoutCents,
          driver_amount_cents: refAmt,
          status:              'pending',
        });
        const referrer        = await sbGetOne(env, 'drivers', `id=eq.${referrerId}&select=total_earnings_cents,referral_earnings`);
        const refCurrent      = referrer?.total_earnings_cents || 0;
        const refCurrentEarns = parseFloat(referrer?.referral_earnings || 0);
        await sbPatch(env, 'drivers', `id=eq.${referrerId}`, {
          total_earnings_cents: refCurrent + refAmt,
          referral_earnings: parseFloat((refCurrentEarns + refAmt / 100).toFixed(4)),
        });
      }
    }
  } catch(e) {
    // Log but always return 200 — MaxBounty retries on non-200
    console.error('handleApiConversion error:', e.message);
  }

  return new Response('OK', { status: 200 });
}

// ═══════════════════════════════════════════════════════════════
// COMMISSION ENGINE
// ═══════════════════════════════════════════════════════════════

async function calculateCommissions(env) {
  try {
    const convs = await sbGet(env, 'conversions', 'commission_calculated=eq.false&select=*');
    for (const conv of convs) {
      if (!conv.gross_amount_cents || !conv.driver_id) continue;
      const driverAmt = Math.floor(conv.gross_amount_cents * 0.20);
      const commRow = await sbPost(env, 'commissions', { driver_id:conv.driver_id, conversion_id:conv.id, type:'truck_conversion', gross_amount_cents:conv.gross_amount_cents, driver_amount_cents:driverAmt, status:'pending' });
      await sbPatch(env, 'conversions', `id=eq.${conv.id}`, { commission_calculated:true, commission_id:commRow?.id||null });
      const refs = await sbGet(env, 'referrals', `referred_driver_id=eq.${conv.driver_id}&select=referrer_driver_id`);
      if (refs[0]) {
        const refAmt = Math.floor(conv.gross_amount_cents * 0.10);
        await sbPost(env, 'commissions', { driver_id:refs[0].referrer_driver_id, conversion_id:conv.id, type:'referral_override', gross_amount_cents:conv.gross_amount_cents, driver_amount_cents:refAmt, status:'pending' });
      }
    }
  } catch(e) { console.error('calculateCommissions error:', e.message); }
}

async function runMonthlyCommissions(env) {
  await calculateCommissions(env);
}

